function setupForm({doc, updateField, call, router, toast, $dialog, createToast ,applyFilters}) {

    function update_sub_issue_type(value){
        if(value=="Clearing - Payout") {
            options = ["Payout Pending"]
            applyFilters("sub_issue_type",options)
        }

        else if(value=="Clearing - Settlement") {
            options = ["Settlement Delay"]
            applyFilters("sub_issue_type",options)
        }

        else if(value=="Compliance - KYC") {
            options = ["KYC Update"]
            applyFilters("sub_issue_type",options)
        }

        else if(value=="Compliance - Reporting") {
            options = ["Regulatory Filing"]
            applyFilters("sub_issue_type",options)
        }

        else if(value=="IT - Portal Access") {
            options = ["Login Issue","Password Reset"]
            applyFilters("sub_issue_type",options)
        }

        else if(value=="IT - System Downtime") {
            options = ["System Outage"]
            applyFilters("sub_issue_type",options)
        }

        else if(value=="Trading - Margin Query") {
            options = ["Price Mismatch"]
            applyFilters("sub_issue_type",options)
        }

        else if(value=="Trading - Order Entry") {
            options = ["Order Rejection"]
            applyFilters("sub_issue_type",options)
        }

        else {
            applyFilters("sub_issue_type",[])
        }
    }


   return {
        onChange: {
            ticket_type: (newVal) => update_sub_issue_type(newVal)
        }
    }

}
